const amqplib = require('amqplib');
const crypto = require('crypto');

// In production, use a proper secret management service (AWS Secrets Manager, HashiCorp Vault, etc.)
const SHARED_SECRET = process.env.MESSAGE_SIGNING_SECRET;
if (!SHARED_SECRET) {
  console.error('FATAL: MESSAGE_SIGNING_SECRET environment variable is required');
  process.exit(1);
}

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';
const DEAD_LETTER_QUEUE = `${QUEUE_NAME}.dlq`;
const MAX_RETRY_COUNT = 3;

// Verify HMAC signature on incoming messages
function verifyMessageSignature(messageBody, signature) {
  if (!signature) return false;
  const expectedSignature = crypto
    .createHmac('sha256', SHARED_SECRET)
    .update(messageBody)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

// Strict schema validation for payment messages
function validatePaymentMessage(payment) {
  const errors = [];

  if (!payment || typeof payment !== 'object') {
    return { valid: false, errors: ['Message must be a JSON object'] };
  }

  const requiredFields = ['paymentId', 'amount', 'currency', 'action', 'timestamp'];
  for (const field of requiredFields) {
    if (!(field in payment)) {
      errors.push(`Missing required field: ${field}`);
    }
  }

  if (typeof payment.paymentId !== 'string' || !/^[a-zA-Z0-9\-]{1,64}$/.test(payment.paymentId)) {
    errors.push('paymentId must be an alphanumeric string (max 64 chars)');
  }

  if (typeof payment.amount !== 'number' || payment.amount <= 0 || payment.amount > 1000000) {
    errors.push('amount must be a positive number up to 1,000,000');
  }

  const allowedCurrencies = ['USD', 'EUR', 'GBP', 'CAD', 'AUD'];
  if (!allowedCurrencies.includes(payment.currency)) {
    errors.push(`currency must be one of: ${allowedCurrencies.join(', ')}`);
  }

  const allowedActions = ['charge', 'refund', 'authorize', 'capture', 'void'];
  if (!allowedActions.includes(payment.action)) {
    errors.push(`action must be one of: ${allowedActions.join(', ')}`);
  }

  // Reject messages older than 5 minutes to prevent replay attacks
  if (payment.timestamp) {
    const messageAge = Date.now() - new Date(payment.timestamp).getTime();
    if (messageAge > 5 * 60 * 1000 || messageAge < -30000) {
      errors.push('Message timestamp is too old or in the future (possible replay attack)');
    }
  }

  return { valid: errors.length === 0, errors };
}

// Idempotency tracking (use Redis or a database in production)
const processedMessageIds = new Map();
const IDEMPOTENCY_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

function isAlreadyProcessed(paymentId, action) {
  const key = `${paymentId}:${action}`;
  if (processedMessageIds.has(key)) {
    return true;
  }
  processedMessageIds.set(key, Date.now());

  // Clean up old entries
  for (const [k, v] of processedMessageIds.entries()) {
    if (Date.now() - v > IDEMPOTENCY_TTL_MS) {
      processedMessageIds.delete(k);
    }
  }
  return false;
}

