async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set up dead letter exchange for failed messages
    await channel.assertExchange('payment_events.dlx', 'direct', { durable: true });
    await channel.assertQueue(DEAD_LETTER_QUEUE, { durable: true });
    await channel.bindQueue(DEAD_LETTER_QUEUE, 'payment_events.dlx', QUEUE_NAME);

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'payment_events.dlx',
        'x-dead-letter-routing-key': QUEUE_NAME,
      },
    });

    // Process one message at a time for payment safety
    await channel.prefetch(1);

    console.log(`Payment consumer started. Listening on queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const rawContent = msg.content.toString();
      const messageHeaders = msg.properties.headers || {};
      const signature = messageHeaders['x-message-signature'];
      const correlationId = msg.properties.correlationId || 'unknown';

      console.log(`Received message (correlationId: ${correlationId})`);

      // Step 1: Verify message signature
      if (!verifyMessageSignature(rawContent, signature)) {
        console.error(
          `SECURITY: Message signature verification FAILED (correlationId: ${correlationId}). ` +
          'Rejecting message. This may indicate tampering or an unauthorized publisher.'
        );
        // Reject without requeue — send to DLQ for investigation
        channel.nack(msg, false, false);
        return;
      }

      // Step 2: Parse JSON safely
      let payment;
      try {
        payment = JSON.parse(rawContent);
      } catch (parseError) {
        console.error(`Failed to parse message JSON (correlationId: ${correlationId}):`, parseError.message);
        channel.nack(msg, false, false);
        return;
      }

      // Step 3: Validate message schema
      const validation = validatePaymentMessage(payment);
      if (!validation.valid) {
        console.error(
          `Validation failed for payment message (correlationId: ${correlationId}):`,
          validation.errors
        );
        channel.nack(msg, false, false);
        return;
      }

      // Step 4: Idempotency check
      if (isAlreadyProcessed(payment.paymentId, payment.action)) {
        console.warn(
          `Duplicate message detected: ${payment.paymentId}:${payment.action} ` +
          `(correlationId: ${correlationId}). Acknowledging without reprocessing.`
        );
        channel.ack(msg);
        return;
      }

      // Step 5: Process the payment
      try {
        const result = await processPayment(payment);
        console.log(`Payment processed successfully:`, result);
        channel.ack(msg);
      } catch (processingError) {
        const retryCount = (messageHeaders['x-retry-count'] || 0);
        console.error(
          `Payment processing failed (correlationId: ${correlationId}, ` +
          `retry: ${retryCount}/${MAX_RETRY_COUNT}):`,
          processingError.message
        );

        if (retryCount < MAX_RETRY_COUNT) {
          // Requeue with incremented retry count
          // Nack and let it go back to queue, or republish with updated headers
          console.log(`Requeueing message for retry...`);
          channel.nack(msg, false, true);
        } else {
          console.error(`Max retries exceeded for payment ${payment.paymentId}. Sending to DLQ.`);
          channel.nack(msg, false, false);
        }
      }
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`Received ${signal}. Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
      } catch (err) {
        console.error('Error during shutdown:', err.message);
      }
      process.exit(0);
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));

    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('RabbitMQ connection closed. Exiting...');
      process.exit(1);
    });

  } catch (error) {
    console.error('Failed to start payment consumer:', error.message);
    process.exit(1);
  }
}

// Utility: Example of how publishers should sign messages
function examplePublisherSignMessage(messageBody) {
  const signature = crypto
    .createHmac('sha256', SHARED_SECRET)
    .update(messageBody)
    .digest('hex');
  return signature;
}

startConsumer();